/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // A is MxM, B is MxN
    // B := alpha * A^T * B
    //
    // We perform the computation in a cache‑friendly manner,
    // and parallelise the outermost loop.
    // The result is mathematically identical to the reference implementation.

#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // Fetch the i-th row of B once per j loop
        for (int j = 0; j < n; ++j) {
            double vij = B[i][j];                   // local copy
            double *a_row = &A[i][i + 1];           // pointer to A[k][i] where k>i

            // Accumulate contribution from rows k = i+1 .. m-1
            for (int k = i + 1; k < m; ++k) {
                vij += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * vij;                  // store result
        }
    }
}
