void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* ---------- 1. compute column means  ---------- */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i)
            s += data[i][j];
        mean[j] = s / n;
    }

    /* ---------- 2. center the data  ---------- */
    #pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j)
            row[j] -= mean[j];
    }

    /* ---------- 3. compute covariance matrix (upper triangle)  ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // Compute all cov[i][j] where j >= i
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            double v = sum / (n - 1);
            cov[i][j] = v;
            cov[j][i] = v;   // fill symmetric entry
        }
    }
}
