/**
 * Optimised Jacobi kernel
 *
 * The original algorithm performs two stencil updates per time step.
 * This version uses raw pointers and OpenMP to allocate work across
 * 8 threads on an x86‑64 machine.  It preserves the exact numerical
 * behavior (using the same constant 0.33333).
 */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    // Avoid bounds checks during the inner loops – write helpers as local
    constexpr double coeff = 0.33333;
    double *a = A.data();
    double *b = B.data();

    // OpenMP parallelisation: the two inner loops are independent in each
    // time step, so we can parallelise them separately.
    for (int t = 0; t < tsteps; ++t) {
        // Update B from A
        #pragma omp parallel for schedule(static, 256) shared(a,b,coeff)
        for (int i = 1; i < n - 1; ++i)
            b[i] = coeff * (a[i-1] + a[i] + a[i+1]);

        // Update A from B
        #pragma omp parallel for schedule(static, 256) shared(a,b,coeff)
        for (int i = 1; i < n - 1; ++i)
            a[i] = coeff * (b[i-1] + b[i] + b[i+1]);
    }
}
