        const double ri = r[i];
        const std::vector<double>& Ai = A[i];

        /* accumulate into q[i] and into the shared vector s[j] */
        for (int j = 0; j < m; ++j) {
            const double aij = Ai[j];
            s[j] += ri * aij;   /* accumulate s[j] – race free (reduction) */
            qi += aij + p[j];
        }
        q[i] = qi;
    }
