void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {
    // Parallelise over the outermost dimension, i.e. over the rows of C.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *c_row = C[i].data();           // pointer to the i‑th row of C
        const double *a_row_i = A[i].data();   // pointer to the i‑th row of A

        // 1) Scale the lower‑triangle part of C by beta
        for (int j = 0; j <= i; ++j) {
            c_row[j] *= beta;
        }

        // 2) Accumulate alpha*A[i][k]*A[l][k] into C[i][l] for l <= i
        for (int k = 0; k < m; ++k) {
            double aik = a_row_i[k];
            for (int l = 0; l <= i; ++l) {
                c_row[l] += alpha * aik * A[l][k];
            }
        }
    }
}
