/* Optimised QR Decomposition with Modified Gram–Schmidt.
 * Uses OpenMP for parallelism and continuous access patterns
 * to maximise cache utilisation.  The interface is identical
 * to the original kernel. */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    /* Basic sanity: A is m×n, R and Q are n×n */
#pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        /* 1. Compute ||A[:,k]||_2   (parallel reduction) */
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = A[i][k];
            nrm += val * val;
        }
        R[k][k] = std::sqrt(nrm);

        /* 2. Normalise column k into Q[:,k] */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        /* 3. Orthogonalise remaining columns */
        for (int j = k + 1; j < n; ++j) {
            /* Compute R[k][j] = <Q[:,k], A[:,j]> */
            double rkj = 0.0;
#pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i) {
                rkj += Q[i][k] * A[i][j];
            }
            R[k][j] = rkj;

            /* Subtract the projection from A[:,j] */
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * rkj;
            }
        }
    }
}
