/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) 
{
    // Allocate a temporary vector once. Size n is small enough for stack use,
    // but we keep it on the heap for safety with arbitrary n.
    std::vector<double> z;
    z.resize(n);

    // Base case
    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    // Main loop
    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = sum_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        const double* r_ptr = r.data() + k - 1;   // points to r[k-1]
        const double* y_ptr = y.data();           // points to y[0]
        for (int i = 0; i < k; ++i) {
            sum += (*r_ptr--) * (*y_ptr++);
        }

        // Compute new alpha
        alpha = -(r[k] + sum) / beta;

        // Compute z[0..k-1] = y[0..k-1] + alpha * y[k-1..0]
        const double* y_rev_ptr = y.data() + k - 1;   // y[k-1]
        double* z_ptr = z.data();
        const double* y_ptr2 = y.data();             // y[0]
        for (int i = 0; i < k; ++i) {
            *z_ptr++ = *y_ptr2++ + alpha * (*y_rev_ptr--);
        }

        // Copy z back into y[0..k-1]
        std::copy(z.data(), z.data() + k, y.data());

        // Set the new coefficient
        y[k] = alpha;
    }
}
