void kernel_gemm(int ni, int nj, int nk,
                 double alpha, double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C) {
    // Convert the 2‑D std::vector data to contiguous 1‑D arrays for fast access
    const size_t elemsA = static_cast<size_t>(ni) * nk;
    const size_t elemsB = static_cast<size_t>(nk) * nj;
    const size_t elemsC = static_cast<size_t>(ni) * nj;

    // allocate contiguous buffers
    std::vector<double> a(elemsA);
    std::vector<double> b(elemsB);
    std::vector<double> c(elemsC);

    // copy data into contiguous buffers (single thread, cheap)
    for (int i = 0; i < ni; ++i)
        std::memcpy(&a[i * nk], A[i].data(), nk * sizeof(double));
    for (int k = 0; k < nk; ++k)
        std::memcpy(&b[k * nj], B[k].data(), nj * sizeof(double));
    for (int i = 0; i < ni; ++i)
        std::memcpy(&c[i * nj], C[i].data(), nj * sizeof(double));

    // Perform the GEMM with OpenMP parallelisation.
    // The outer “i” loop is parallel, the inner loops are executed sequentially per row.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* ci = &c[i * nj];
        // Scale existing C by beta
        for (int j = 0; j < nj; ++j) ci[j] *= beta;

        // Compute alpha * A[i, :] * B
        const double* ai = &a[i * nk];
        for (int k = 0; k < nk; ++k) {
            double aik = ai[k] * alpha;
            const double* bk = &b[k * nj];
            for (int j = 0; j < nj; ++j)
                ci[j] += aik * bk[j];
        }
    }

    // Copy result back into the original C vector
    for (int i = 0; i < ni; ++i)
        std::memcpy(C[i].data(), &c[i * nj], nj * sizeof(double));
}
