/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A) {
    const int B = 64;                 // blocking factor (tune for L2 cache size)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // compute the i‑th row column by column
        for (int je = 0; je < i; je += B) {
            int jend = std::min(i, je + B);
            for (int j = je; j < jend; ++j) {
                // update A[i][j] using the already computed part of
                // row i and column j
                for (int k = je; k < j; ++k) {
                    A[i][j] -= A[i][k] * A[j][k];
                }
                // remainder that lies before the current block
                for (int k = 0; k < je; ++k) {
                    A[i][j] -= A[i][k] * A[j][k];
                }
                A[i][j] /= A[j][j];
            }
        }

        // diagonal element
        double sum = 0.0;
        for (int ke = 0; ke < i; ke += B) {
            int kend = std::min(i, ke + B);
            for (int k = ke; k < kend; ++k) {
                sum += A[i][k] * A[i][k];
            }
        }
        A[i][i] -= sum;
        A[i][i] = std::sqrt(A[i][i]);
    }
}
