    std::vector<double> flatA;

    if (flatA.size() != static_cast<size_t>(nr) * nq * np)
        flatA.resize(static_cast<size_t>(nr) * nq * np);

    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
            for (int s = 0; s < np; ++s)
                flatA[idx3(r,q,s,nq,np)] = A[r][q][s];

    /* Main work: parallelise the outer loops */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            /* Accumulate matrix–vector products */
            for (int p = 0; p < np; ++p) {
