/*
 * Same functional behaviour as the original kernel.
 * Assumes A is a square matrix stored as a vector of contiguous rows.
 *
 * The outer loop over rows cannot be parallelised because each
 * element A[i][j] depends on previously computed elements
 * in the same row.  The inner loop that updates the upper
 * triangle of the row (j >= i) is independent across columns,
 * so it is parallelised with OpenMP.
 */

static inline double* row_ptr(std::vector<std::vector<double>>& A, std::size_t i)
{
    return A[i].data();
}

void kernel_lu(int n,
               std::vector<std::vector<double>>& A)
{
    for (int i = 0; i < n; ++i) {
        double* a_i = row_ptr(A, i);

        /* First part: lower triangle (j < i) – sequential */
        for (int j = 0; j < i; ++j) {
            double sum = a_i[j];
            double* a_k = nullptr;
            for (int k = 0; k < j; ++k) {
                a_k = row_ptr(A, i);
                a_i[j] -= a_k[k] * row_ptr(A, k)[j];
            }
            a_i[j] = sum - a_i[j];
            a_i[j] /= row_ptr(A, j)[j];
        }

        /* Second part: upper triangle (j >= i) – parallelised */
#pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double* a_k = nullptr;
            for (int k = 0; k < i; ++k) {
                a_k = row_ptr(A, i);
                a_i[j] -= a_k[k] * row_ptr(A, k)[j];
            }
        }
    }
}
