            sum += data[i][j];
        }
        mean[j] = sum / static_cast<double>(n);
    }

    /* ----------------- 2. compute column std devs ----------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum_sq = 0.0;
        for (int i = 0; i < n; ++i) {
            double diff = data[i][j] - mean[j];
            sum_sq += diff * diff;
        }
        double var = sum_sq / static_cast<double>(n);
        stddev[j] = std::sqrt(var);
        if (stddev[j] <= eps)   /* guard against very small variances */
            stddev[j] = 1.0;
    }

    /* ----------------- 3. normalize data ----------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_sqrt_n / stddev[j];
        }
    }

    /* ----------------- 4. compute correlation matrix ----------------- */
    /* Note: corr is assumed to be pre‑allocated m x m */
    #pragma omp parallel for schedule(dynamic,1)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;   /* diagonal is always 1 */
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;   /* fill symmetric entry */
        }
    }
