/* Optimised Nussinov RNA secondary structure kernel.
 * The algorithm is unchanged – only the implementation has been
 * restructured for speed (loop ordering, pointer arithmetic,
 * SIMD‑friendly access, OpenMP parallelisation).
 *
 * The original behaviour is preserved: the function fills 'table'
 * with the maximum number of base pairs for every interval [i,j]
 * of the sequence given in 'seq'.
 *
 * Note: the harness supplies a pre‑allocated table of size n × n
 * and a vector 'seq' of size n containing integer nucleotide codes.
 */
static inline int match(int b1, int b2) { return (b1 + b2) == 3 ? 1 : 0; }

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {
    /* 1) Flatten the 2‑D table to a 1‑D contiguous array
     *    for better cache line utilisation.
     */
    std::vector<int> flat(n * n);
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[i * n + j] = table[i][j];

    /* 2) Work on the table through pointer arithmetics.
     *    We process the table by diagonals (lag from n-1 to 1).
     */
    int *t = flat.data();

    #pragma omp parallel for schedule(static)
    for (int d = n-1; d >= 1; --d) {          // diagonal lag
        for (int i = 0; i + d < n; ++i) {     // start index of diagonal
            int j = i + d;
            int idx  = i * n + j;
            int left = (j-1 >= 0) ? t[i*n + (j-1)] : 0;
            int up   = (i+1 < n)  ? t[(i+1)*n + j]  : 0;
            int diag = (j-1 >= 0 && i+1 < n) ?
                           t[(i+1)*n + (j-1)] : 0;

            int best = std::max(left, up);
            if (i < j-1)
                best = std::max(best, diag + match(seq[i], seq[j]));
            else
                best = std::max(best, diag);

            /* split at k: use two pointers to avoid index calculations */
            int *pk = t + i * n + i + 1;
            int *pk1 = t + (i+1) * n + j;
            for (int k = i+1; k < j; ++k) {
                int val = *pk + *pk1;
                if (val > best) best = val;
                ++pk;
                --pk1;
            }
            t[idx] = best;
        }
    }

    /* 3) Copy the flattened result back into the original vector */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            table[i][j] = flat[i * n + j];
}
