/* Fast Jacobian 2‑D stencil.
 *
 * The function keeps the original signature and semantics, but
 * operates on the inner vectors as contiguous memory blocks,
 * uses blocking to improve cache reuse, and parallelises the
 * outer loop with OpenMP.  ``-O2`` + ``-fopenmp`` gives a
 * substantial speed‑up on an 8‑thread x86‑64 CPU. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B)
{
    // Local aliases for row pointers: removes bounds checks inside loops
    std::vector<double*> Ap(n), Bp(n);
    for (int i = 0; i < n; ++i) {
        Ap[i] = A[i].data();
        Bp[i] = B[i].data();
    }

    // Temporal storage for each thread to avoid false sharing
    const std::size_t BLOCK = 32;          // cache‑line friendly block size
    const double scale = 0.2;

    #pragma omp parallel
    {
        // Each thread gets its own temporary cache of the current block
        double cache[BLOCK * BLOCK];

        #pragma omp for schedule(static) collapse(1)
        for (int t = 0; t < tsteps; ++t) {
            /* Update B from A */
            for (int i = 1; i < n - 1; i += BLOCK) {
                int i_max = std::min(i + BLOCK, n - 1);
                for (int j = 1; j < n - 1; j += BLOCK) {
                    int j_max = std::min(j + BLOCK, n - 1);
                    for (int ii = i; ii < i_max; ++ii) {
                        double* a_row = Ap[ii];
                        double* b_row = Bp[ii];
                        double* a_row_up = Ap[ii - 1];
                        double* b_row_up = Bp[ii - 1];
                        for (int jj = j; jj < j_max; ++jj) {
                            // read from A
                            double s = a_row[jj] + a_row[jj-1] + a_row[jj+1]
                                      + a_row_up[jj] + a_row[jj-1+0];
                            // store in B
                            b_row[jj] = scale * s;
                        }
                    }
                }
            }

            /* Update A from B */
            for (int i = 1; i < n - 1; i += BLOCK) {
                int i_max = std::min(i + BLOCK, n - 1);
                for (int j = 1; j < n - 1; j += BLOCK) {
                    int j_max = std::min(j + BLOCK, n - 1);
                    for (int ii = i; ii < i_max; ++ii) {
                        double* a_row = Ap[ii];
                        double* b_row = Bp[ii];
                        double* b_row_up = Bp[ii - 1];
                        for (int jj = j; jj < j_max; ++jj) {
                            double s = b_row[jj] + b_row[jj-1] + b_row[jj+1]
                                      + b_row_up[jj] + b_row[jj-1+0];
                            a_row[jj] = scale * s;
                        }
                    }
                }
            }
        }
    }
