        /* Substitution for lower part */
        for (int j = 0; j < i; ++j) {
            double w = buf[i * n + j];
            for (int k = 0; k < j; ++k)
                w -= buf[i * n + k] * buf[k * n + j];
            buf[i * n + j] = w / buf[j * n + j];
        }

        /* Substitution for upper part – can be parallelised over j */
        #pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double w = buf[i * n + j];
            for (int k = 0; k < i; ++k)
                w -= buf[i * n + k] * buf[k * n + j];
            buf[i * n + j] = w;
        }
    }

    /* Copy back the LU‑factored matrix into the original vector of vectors */
    for (int i = 0; i < n; ++i)
        std::memcpy(A[i].data(), &buf[i * n], n * sizeof(double));

    /* -------- Forward substitution (Ly = b) -------- */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j)
            w -= A[i][j] * y[j];
        y[i] = w;
