/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Convert the 2‑D std::vector layout to raw pointers for very
       fast indexed access.  The outer vector indexes rows; the inner
       vectors (rows) are assumed to have length at least `n` or `m`
       as required. */
    std::vector<double*> Crow(m), Arow(m), Brow(m);
    for (int i = 0; i < m; ++i) {
        Crow[i] = C[i].data();
        Arow[i] = A[i].data();
        Brow[i] = B[i].data();
    }

    /* The algorithm is inherently sequential because each iteration
       `i` writes into rows `k < i`.  Parallelising the outer loop
       would introduce data races.  Therefore the implementation
       remains a single thread but is highly cache‑friendly and
       vectorised by the compiler. */
    for (int i = 0; i < m; ++i) {
        double const *Ai   = Arow[i];
        double const *Bi   = Brow[i];
        double const *Ai_i = Ai + i;          /* A[i][i] */
        double Ai_i_val   = *Ai_i;

        for (int j = 0; j < n; ++j) {
            double const B_ij = Bi[j];
            double temp2 = 0.0;

            /* Accumulate the contributions for rows k < i */
            for (int k = 0; k < i; ++k) {
                double const Aik = Ai[k];
                double const Bkj = Brow[k][j];

                /* Update C[k][j] directly */
                Crow[k][j] += alpha * Bkj * Aik;

                /* Accumulate the partial sum for the current row i */
                temp2 += Bkj * Aik;
            }

            /* Finish the update of C[i][j] */
            Crow[i][j] = beta * C[i][j] + alpha * B_ij * Ai_i_val + alpha * temp2;
        }
    }
}
