            double* vcol   = v[i].data();
            double* pcol   = p[i].data();
            double* qcol   = q[i].data();

            vcol[0]       = 1.0;
            pcol[0]       = 0.0;
            qcol[0]       = vcol[0];

            /* forward j-loop */
